#Alignerimport numpy as npdef align_xy(sample_spectra, gcms_df):    """    Aligns X (Raman spectra), Y (GC-MS data), and group labels based on common sample IDs.    Parameters:        sample_spectra (dict): Dictionary of spectra by sample ID.        gcms_df (pd.DataFrame): GC-MS data with sample IDs as the index.        sample_groups (list): List of group labels aligned with each spectrum.    Returns:        filtered_X (np.ndarray): Aligned X data (n_samples, n_features).        filtered_Y (np.ndarray): Aligned Y data (n_samples, n_targets).        filtered_sample_ids (list): Aligned sample IDs.        filtered_group_labels (list): Group labels aligned with X.    """    X = []    sample_ids = []    group_labels = []    for sample_id, spectra in sample_spectra.items():        spectral_data = np.array([spectrum.spectral_data for spectrum in spectra])        X.extend(spectral_data)  # one row per spectrum        sample_ids.extend([sample_id] * len(spectral_data))        group = sample_id.split('-')[0]        group_labels.extend([group] * len(spectral_data))    X = np.vstack(X)    common_ids = set(sample_ids).intersection(set(gcms_df.index))    unmatched_ids = set(sample_ids).symmetric_difference(set(gcms_df.index))    if unmatched_ids:        print(f"Could not match data for these IDs: {unmatched_ids}")    filtered_X = []    filtered_sample_ids = []    filtered_group_labels = []    for i, sample_id in enumerate(sample_ids):        if sample_id in common_ids:            filtered_X.append(X[i])            filtered_sample_ids.append(sample_id)            filtered_group_labels.append(group_labels[i])    filtered_X = np.vstack(filtered_X)    filtered_Y = gcms_df.loc[filtered_sample_ids]    return filtered_X, filtered_Y, filtered_sample_ids, filtered_group_labels, unmatched_idsdef align_group_xy(group_spectra, gcms_df):    """    Align X (group-averaged spectra) and Y (group-averaged GC-MS) based on group IDs.    Parameters:        group_spectra (dict): Keys are group IDs, values are ramanspy.Spectrum objects.        gcms_df (pd.DataFrame): GC-MS targets with group IDs as index.    Returns:        filtered_X (np.ndarray)        filtered_Y (pd.DataFrame)        filtered_group_ids (list)        filtered_group_labels (list)    """    X = []    group_ids = []    # Check for match between group_spectra and GCMS table    input_ids = set(group_spectra.keys())    target_ids = set(gcms_df.index)    common_ids = input_ids.intersection(target_ids)    unmatched_ids = input_ids.symmetric_difference(target_ids)    if unmatched_ids:        print(f"⚠️ Could not match GC-MS data for these group IDs: {unmatched_ids}")    for group_id in sorted(common_ids):        spectrum = group_spectra[group_id]        X.append(spectrum.spectral_data)        group_ids.append(group_id)    if not X:        raise ValueError("No overlapping group IDs between spectra and GC-MS table.")    X = np.vstack(X)    Y = gcms_df.loc[group_ids]    return X, Y, group_ids, group_ids, unmatched_ids